mapper.select:
SELECT b.*, c.name as courtName, u.username as userName, u.phone as userPhone, CASE WHEN b.cancel_request_status = 1 AND b.status = 1 THEN '待付款（取消审核中）' WHEN b.cancel_request_status = 2 AND b.status = 1 THEN '待付款（取消已驳回）' WHEN b.payment_verify_status = 1 AND b.status = 1 THEN '待付款（付款审核中）' WHEN b.payment_verify_status = 2 AND b.status = 1 THEN '待付款（付款审核已驳回）' WHEN b.status = 0 THEN '已取消' WHEN b.status = 1 THEN '待付款' WHEN b.status = 2 THEN '已付款' WHEN b.status = 3 THEN '已完成' WHEN b.status = 4 THEN '已过期' ELSE '未知' END as statusText FROM booking b LEFT JOIN court c ON b.court_id = c.id LEFT JOIN user u ON b.user_id = u.id
AND (b.booking_no LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR b.contact_name LIKE CONCAT('%', #{keyword}, '%') OR b.contact_phone LIKE CONCAT('%', #{keyword}, '%'))
AND b.court_id = #{courtId}
AND b.user_id = #{userId}
AND b.status = #{status}
AND b.booking_date >= #{startDate}
AND b.booking_date <= #{endDate}
ORDER BY b.booking_date DESC, b.start_time DESC, b.create_time DESC

SELECT COUNT(*)
FROM booking
WHERE court_id = #{courtId}
AND booking_date = #{bookingDate}
AND status IN (1, 2, 3)  

    AND id != #{excludeId}

AND (
(start_time < #{endTime} AND end_time > #{startTime})
)

mapper.update:
UPDATE booking
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT COALESCE(SUM(duration), 0)
FROM booking
WHERE court_id = #{courtId}
  AND booking_date = #{bookingDate}
  AND status IN (1, 2, 3)

  AND id != #{excludeId}

SELECT start_time AS startTime, end_time AS endTime
FROM booking
WHERE court_id = #{courtId}
  AND booking_date = #{bookingDate}
  AND status IN (1, 2, 3)

  AND id != #{excludeId}

SELECT c.id AS courtId, c.name AS courtName, COUNT(b.id) AS bookingCount, COALESCE(SUM(b.duration), 0) AS totalHours, COALESCE(SUM(b.total_amount), 0) AS totalAmount, COALESCE(SUM(CASE WHEN b.status IN (2, 3) THEN b.total_amount ELSE 0 END), 0) AS paidAmount, COALESCE(SUM(CASE WHEN b.status IN (2, 3) THEN 1 ELSE 0 END), 0) AS paidCount FROM court c LEFT JOIN booking b ON c.id = b.court_id AND b.status IN (1, 2, 3, 0)
AND b.booking_date >= #{startDate}
AND b.booking_date <= #{endDate}
GROUP BY c.id, c.name ORDER BY bookingCount DESC, paidAmount DESC

SELECT u.id AS userId, u.username AS username, u.real_name AS realName, u.phone AS phone, COUNT(b.id) AS bookingCount, COALESCE(SUM(b.duration), 0) AS totalHours, COALESCE(SUM(b.total_amount), 0) AS totalAmount, COALESCE(SUM(CASE WHEN b.status IN (2, 3) THEN 1 ELSE 0 END), 0) AS paidCount, COALESCE(SUM(CASE WHEN b.status IN (2, 3) THEN b.total_amount ELSE 0 END), 0) AS paidAmount, COALESCE(SUM(CASE WHEN b.status = 0 THEN 1 ELSE 0 END), 0) AS canceledCount FROM user u LEFT JOIN booking b ON u.id = b.user_id AND b.status IN (0, 1, 2, 3)
AND b.booking_date >= #{startDate}
AND b.booking_date <= #{endDate}
WHERE u.role = 1 GROUP BY u.id, u.username, u.real_name, u.phone ORDER BY bookingCount DESC, paidAmount DESC
